namespace QAHub.Api.Domain.Releases;
public sealed class ReleaseChecklistItem{private ReleaseChecklistItem(){}public ReleaseChecklistItem(Guid releaseId,string code,string label,bool required){Id=Guid.NewGuid();ReleaseId=releaseId;Code=code.Trim();Label=label.Trim();IsRequired=required;}public Guid Id{get;private set;}public Guid ReleaseId{get;private set;}public string Code{get;private set;}=string.Empty;public string Label{get;private set;}=string.Empty;public bool IsRequired{get;private set;}public bool IsCompleted{get;private set;}public string CompletedBy{get;private set;}=string.Empty;public DateTimeOffset? CompletedAtUtc{get;private set;}public void SetCompleted(bool completed,string actor){IsCompleted=completed;CompletedBy=completed?actor.Trim():string.Empty;CompletedAtUtc=completed?DateTimeOffset.UtcNow:null;}}
